INSERT INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "duration_minutes", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (1, '玉米', '很嫩的玉米粒，许多鱼爱吃，不出意外的话坐你隔壁的钓友也爱吃。', 1, '钓鱼成功率+2%', 0, 10, 1, 0.02, 0, 0, 1, 1, 1);
